import 'package:flutter/material.dart';
import '../models/app_models.dart';
import '../services/api_service.dart';

class DriversScreen extends StatefulWidget{final ApiService api; const DriversScreen({super.key,required this.api}); @override State<DriversScreen> createState()=>_DriversScreenState();}
class _DriversScreenState extends State<DriversScreen>{List<DriverRow> drivers=[]; bool loading=true; @override void initState(){super.initState();load();} Future<void> load()async{final d=await widget.api.drivers();setState(() { drivers=(d['drivers'] as List).map((e)=>DriverRow.fromJson(Map<String,dynamic>.from(e))).toList(); loading=false; });}
 Future<void> add()async{final name=TextEditingController();final phone=TextEditingController();final pass=TextEditingController(text:'123456');await showDialog(context:context,builder:(c)=>AlertDialog(title:const Text('إضافة مندوب'),content:Column(mainAxisSize:MainAxisSize.min,children:[TextField(controller:name,decoration:const InputDecoration(labelText:'الاسم')),TextField(controller:phone,decoration:const InputDecoration(labelText:'الهاتف')),TextField(controller:pass,decoration:const InputDecoration(labelText:'كلمة المرور'))]),actions:[TextButton(onPressed:()=>Navigator.pop(c),child:const Text('إلغاء')),FilledButton(onPressed:()async{await widget.api.createDriver({'name':name.text,'phone':phone.text,'password':pass.text,'vehicle_type':'motorcycle'});if(c.mounted)Navigator.pop(c);},child:const Text('حفظ'))]));await load();}
 @override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('المندوبون'),actions:[IconButton(onPressed:add,icon:const Icon(Icons.add)),IconButton(onPressed:load,icon:const Icon(Icons.refresh))]),body:loading?const Center(child:CircularProgressIndicator()):ListView(children:drivers.map((d)=>Card(child:ListTile(title:Text(d.name),subtitle:Text('${d.phone}\nالحالة: ${d.status}\nآخر موقع: ${d.lat}, ${d.lng}')))).toList()));}
